@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput" @bind:after="OnContentChanged"></textarea>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;

    private const string StorageKeyContent = "notepad-content";
    private const string StorageKeyTimestamp = "notepad-timestamp";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import",
                $"./{Components.Layout.NavMenu.AssetsPrefix}Components/Pages/Notepad.razor.js");

            var restored = await module.InvokeAsync<string?>("load", StorageKeyContent);
            if (restored is not null)
            {
                content = restored;
                savedContent = restored;

                var ts = await module.InvokeAsync<string?>("load", StorageKeyTimestamp);
                if (ts is not null && DateTime.TryParse(ts, out var parsed))
                {
                    lastSavedAt = parsed;
                }

                StateHasChanged();
            }

            autoSaveTimer = new System.Threading.Timer(async _ =>
            {
                if (HasUnsavedChanges)
                {
                    await InvokeAsync(async () =>
                    {
                        await Save();
                        StateHasChanged();
                    });
                }
            }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    private bool HasUnsavedChanges => content != savedContent;

    private async Task OnContentChanged()
    {
        await UpdateBeforeUnload();
    }

    private async Task UpdateBeforeUnload()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("setBeforeUnload", HasUnsavedChanges);
        }
    }

    private async Task Save()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("save", StorageKeyContent, content);
            lastSavedAt = DateTime.Now;
            await module.InvokeVoidAsync("save", StorageKeyTimestamp, lastSavedAt.Value.ToString("o"));
            savedContent = content;
            await UpdateBeforeUnload();
        }
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Clear()
    {
        content = string.Empty;
        savedContent = string.Empty;
        lastSavedAt = null;

        if (module is not null)
        {
            await module.InvokeVoidAsync("remove", StorageKeyContent);
            await module.InvokeVoidAsync("remove", StorageKeyTimestamp);
            await UpdateBeforeUnload();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }

        if (module is not null)
        {
            await module.InvokeVoidAsync("setBeforeUnload", false);
            await module.DisposeAsync();
        }
    }
}

export function save(key, value) {
    localStorage.setItem(key, value);
}

export function load(key) {
    return localStorage.getItem(key);
}

export function remove(key) {
    localStorage.removeItem(key);
}

let beforeUnloadHandler = null;

export function setBeforeUnload(enabled) {
    if (enabled && !beforeUnloadHandler) {
        beforeUnloadHandler = (e) => {
            e.preventDefault();
        };
        window.addEventListener("beforeunload", beforeUnloadHandler);
    } else if (!enabled && beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

